// Flatten all products from all boards into one array
const data = $input.first().json;
const allProducts = [];
for (const board of data.boards) {
  for (const product of board.products) {
    allProducts.push({ ...product, boardName: board.name });
  }
}

// Get pinned tracking from workflow static data
const pinnedAsins = $getWorkflowStaticData('global').pinnedAsins ?? [];

// Find unpinned products
const unpinned = allProducts.filter(p => !pinnedAsins.includes(p.asin));

if (unpinned.length === 0) {
  // All products pinned — reset to start a new cycle
  $getWorkflowStaticData('global').pinnedAsins = [];
  return allProducts.slice(0, 5).map(p => ({ json: p }));
}

// Return next 5 to pin
return unpinned.slice(0, 5).map(p => ({ json: p }));

// Match product to its board ID
const product = $('Pick Next 5 Unpinned').all()[$itemIndex].json;
const boards = $('Get My Pinterest Boards').all().map(b => b.json);

const matchingBoard = boards.find(b => 
  b.name.toLowerCase() === product.boardName.toLowerCase()
);

if (!matchingBoard) {
  // Fallback: use first board
  return [{ json: { ...product, boardId: boards[0]?.id ?? 'unknown' } }];
}

return [{ json: { ...product, boardId: matchingBoard.id } }];

// Mark this product as pinned in static workflow data
const asin = $input.first().json.asin ?? $('Match Board ID').first().json.asin;
const storage = $getWorkflowStaticData('global');
if (!storage.pinnedAsins) storage.pinnedAsins = [];
if (asin && !storage.pinnedAsins.includes(asin)) {
  storage.pinnedAsins.push(asin);
}
console.log(`Pinned: ${asin} (${storage.pinnedAsins.length} total pinned)`);
return $input.all();
